import { ZkiraClient } from '@zkira/sdk'
import { Connection, PublicKey } from '@solana/web3.js'

const connection = new Connection('https://api.mainnet-beta.solana.com')
const wallet = // Your wallet adapter

const client = new ZkiraClient({
  connection,
  wallet,
  cluster: 'mainnet-beta' // or 'devnet'
})

const USDC_MINT = new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v')

const { link, escrow } = await client.createPaymentLink({
  amount: 1_000_000_000, // 1000 USDC (6 decimals)
  tokenMint: USDC_MINT,
  expirySeconds: 3600 // Optional: expires in 1 hour
})

console.log('Payment Link:', link)
console.log('Escrow Address:', escrow.toString())

const status = await client.getEscrowStatus(escrow)

if (status.state === 'Claimed') {
  console.log('Payment claimed at:', status.claimedAt)
  console.log('Claimed by:', status.recipient?.toString())
} else if (status.state === 'Active') {
  console.log('Payment waiting to be claimed')
} else if (status.state === 'Refunded') {
  console.log('Payment refunded to sender')
}

// Recipient claims payment privately
